#!/usr/bin/env bash\nset -euo pipefail\n\n# Run as root when needed — container's postCreateCommand runs as the 'vscode' user,\n# escalate if sudo is available.\nSUDO=""\nif [ "$(id -u)" -ne 0 ] && command -v sudo >/dev/null 2>&1; then\n  SUDO="sudo"\nfi\n\necho "MiOS devcontainer: performing post-create setup..."\n\n# 1) Install kubectl (stable) if missing\nif ! command -v kubectl >/dev/null 2>&1; then\n  echo "Installing kubectl..."\n  KUBECTL_VER=$(curl -L -s https://dl.k8s.io/release/stable.txt)\n  ${SUDO} curl -fsSL "https://dl.k8s.io/release/${KUBECTL_VER}/bin/linux/amd64/kubectl" -o /usr/local/bin/kubectl\n  ${SUDO} chmod +x /usr/local/bin/kubectl\nfi\n\n# 2) Install Helm (if missing)\nif ! command -v helm >/dev/null 2>&1; then\n  echo "Installing helm..."\n  curl -fsSL https://raw.githubusercontent.com/helm/helm/main/scripts/get-helm-3 | ${SUDO} bash\nfi\n\n# 3) Add 'vscode' to docker group if docker socket exists and group exists\nif [ -e /var/run/docker.sock ]; then\n  if getent group docker >/dev/null 2>&1; then\n    echo "Adding user to docker group..."\n    ${SUDO} usermod -aG docker $(id -un) || true\n  fi\nfi\n\necho "MiOS devcontainer setup complete. You may need to reload the VS Code window."\n